import { useCallback, useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import DriverSidebar from "../../components/driver/DriverSidebar";
import DriverTopbar from "../../components/driver/DriverTopbar";
import { useAuth } from "../../context/AuthContext";
import { apiRequest } from "../../api/client";
import "../../styles/global.css";
import "../../styles/auth.css";

export default function DriverDashboardPage() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const [history, setHistory] = useState([]);
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [deleting, setDeleting] = useState(false);

  const loadData = useCallback(async () => {
    if (!user?.id) return;
    try {
      setLoading(true);
      const [historyRes, requestsRes] = await Promise.all([
        apiRequest(`/driver/trips/history?driverId=${user.id}`, { method: "GET" }),
        apiRequest(`/driver/trips/requests`, { method: "GET" }),
      ]);
      setHistory(historyRes?.trips || []);
      setRequests(requestsRes?.trips || []);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, [user?.id]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const stats = useMemo(() => {
    const totalTrips = history.length;
    const completed = history.filter((t) => t.status === "completed");
    const totalEarnings = completed.reduce((acc, t) => acc + Number(t.earnings || t.fare || 0), 0);
    const activeTrips = history.filter((t) => ["accepted", "in_progress"].includes(t.status)).length;
    const safetyScore = user?.faceVerified ? 98 : 85;

    return {
      totalTrips,
      totalEarnings: totalEarnings.toFixed(0),
      activeTrips,
      safetyScore,
    };
  }, [history, user]);

  const verificationBadge = user?.faceVerified
    ? { text: "Verification Complete", cls: "ok" }
    : { text: "Verification Pending", cls: "warn" };

  const recentTrips = history.slice(0, 5);

  const today = new Date().toLocaleDateString("en-GB", {
    weekday: "long",
    day: "numeric",
    month: "long",
    year: "numeric",
  });

  const handleDeleteAccount = async () => {
    const ok = window.confirm(
      "Are you sure you want to delete your account? This action cannot be undone."
    );
    if (!ok) return;

    try {
      setDeleting(true);
      await apiRequest(`/driver/account/${user?.id}`, { method: "DELETE" });

      if (logout) await logout();
      localStorage.clear();
      navigate("/login", { replace: true });
    } catch (e) {
      alert(e?.message || "Failed to delete account");
    } finally {
      setDeleting(false);
    }
  };

  return (
    <div className="shell">
      <DriverSidebar />

      <div className="main dashboard-green">
        <DriverTopbar
          title={`Good evening, ${user?.fullNames?.split(" ")[0] || "Driver"}`}
          subtitle={today}
        />

        <section className="card profile-strip">
          <div>
            <div className="strip-label">Driver Profile</div>
            <h2>{user?.fullNames || "Driver Name"}</h2>
            <p>
              {user?.email || "No email"} · {user?.phone || "Not provided"}
            </p>
          </div>
          <span className={`pill pill-${verificationBadge.cls}`}>{verificationBadge.text}</span>
        </section>

        <section className="kpi-grid">
          <article className="kpi-card">
            <div className="kpi-label">Total Trips</div>
            <div className="kpi-value">{stats.totalTrips}</div>
            <div className="kpi-sub">All time</div>
          </article>

          <article className="kpi-card">
            <div className="kpi-label">Total Earnings</div>
            <div className="kpi-value">R{stats.totalEarnings}</div>
            <div className="kpi-sub">Completed trips</div>
          </article>

          <article className="kpi-card">
            <div className="kpi-label">Safety Score</div>
            <div className="kpi-value">{stats.safetyScore}%</div>
            <div className="kpi-sub">Excellent</div>
          </article>
        </section>

        <section style={{ marginTop: 10 }}>
          <h3 className="section-title-clean">Quick Actions</h3>
          <div className="quick-grid">
            <button className="quick-btn" onClick={() => navigate("/driver/trips")}>
              🧾 Trip Requests
            </button>
            <button className="quick-btn" onClick={() => navigate("/driver/trip-history")}>
              📖 Trip History
            </button>
            <button className="quick-btn" onClick={() => navigate("/driver/trips")}>
              📍 Active Trips
            </button>
            <button className="quick-btn" onClick={() => navigate("/driver/notifications")}>
              🔔 Notifications
            </button>
          </div>
        </section>

        <section className="two-col">
          <article className="card info-card">
            <h3>Verification Status</h3>
            <div className="info-row">
              <span>Consent Form</span>
              <span className={`pill ${user?.verificationConsentGiven ? "pill-ok" : "pill-warn"}`}>
                {user?.verificationConsentGiven ? "Signed" : "Pending"}
              </span>
            </div>
            <div className="info-row">
              <span>ID Document</span>
              <span className={`pill ${user?.idDocumentUploaded ? "pill-ok" : "pill-warn"}`}>
                {user?.idDocumentUploaded ? "Uploaded" : "Pending"}
              </span>
            </div>
            <div className="info-row">
              <span>Face Verification</span>
              <span className={`pill ${user?.faceVerified ? "pill-ok" : "pill-warn"}`}>
                {user?.faceVerified ? "Verified" : "Pending"}
              </span>
            </div>
          </article>

          <article className="card info-card">
            <h3>Driver Information</h3>
            <div className="info-row">
              <span>Full Name</span>
              <strong>{user?.fullNames || "—"}</strong>
            </div>
            <div className="info-row">
              <span>Email</span>
              <strong>{user?.email || "—"}</strong>
            </div>
            <div className="info-row">
              <span>Phone</span>
              <strong>{user?.phone || "Not provided"}</strong>
            </div>
            <div className="info-row">
              <span>Vehicle</span>
              <strong>{user?.vehicleModel || "Not set"}</strong>
            </div>
            <div className="info-row">
              <span>Plate</span>
              <strong>{user?.licensePlate || "Not set"}</strong>
            </div>
          </article>
        </section>

        <section style={{ marginTop: 12 }}>
          <h3 className="section-title-clean">Recent Trips</h3>
          <div className="card">
            {loading ? (
              <p style={{ color: "var(--text2)" }}>Loading trips...</p>
            ) : recentTrips.length === 0 ? (
              <p style={{ color: "var(--text2)" }}>No trips yet.</p>
            ) : (
              <div className="recent-list">
                {recentTrips.map((t) => (
                  <div className="recent-item" key={t.id}>
                    <div>
                      <div className="trip-route">{t.pickup} → {t.destination}</div>
                      <div className="trip-sub">
                        {t.date || "N/A"} · {t.passengerName || "Passenger"}
                      </div>
                    </div>
                    <div style={{ textAlign: "right" }}>
                      <div className="trip-fare">{t.fare != null ? `R${t.fare}` : "—"}</div>
                      <span className={`pill status-${t.status || "requested"}`}>
                        {t.status || "requested"}
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </section>

        {requests.length > 0 && (
          <section style={{ marginTop: 12 }}>
            <h3 className="section-title-clean">Open Requests</h3>
            <div className="card">
              <div className="recent-list">
                {requests.slice(0, 3).map((r) => (
                  <div className="recent-item" key={r.id}>
                    <div>
                      <div className="trip-route">{r.pickup} → {r.destination}</div>
                      <div className="trip-sub">Passenger: {r.passengerName}</div>
                    </div>
                    <button className="btn btn-p btn-sm" onClick={() => navigate("/driver/trips")}>
                      Open
                    </button>
                  </div>
                ))}
              </div>
            </div>
          </section>
        )}

        <section className="card dashboard-account-actions" style={{ marginTop: 12 }}>
          <h3 className="section-title-clean">Account</h3>
          <div className="profile-table-actions">
            <button className="quick-btn" onClick={() => navigate("/driver/car-details")}>
              Edit Information
            </button>
            <button className="quick-btn btn-danger" onClick={handleDeleteAccount} disabled={deleting}>
              {deleting ? "Deleting..." : "Delete Account"}
            </button>
          </div>
        </section>
      </div>
    </div>
  );
}
